('033ebc63-8e40-41e7-b2fc-39bfeaffad90', 1, 'THIS TEMP', 'NONE', '{}', '{\"locked_elements\":{\"content\":false,\"fontSize\":false,\"fontStyle\":false,\"borders\":false,\"headerFooter\":false},\"allowAttachments\":false,\"includeTableOfContents\":false}', '[]', '{\"departmentImpacts\":[],\"affectedSystems\":[],\"implementationEffort\":\"medium\",\"trainingRequired\":false}', '', '{\"reviewers\":[{\"userId\":18,\"name\":\"Jane  Doe\",\"email\":\"jane.doe@test.com\",\"department\":\"Finance\",\"role\":\"template_reviewer\",\"status\":\"pending\",\"dueDate\":\"2025-06-17T16:00:00.000Z\"}],\"approvers\":[]}', '{\"content\":{}}', 1, NULL, 1, '2025-06-06 07:18:50', '2025-06-06 07:19:17', 'pending_review', NULL),
('10aa0cfa-332f-44d6-a9ac-e73924c233d9', 1, 'new template july 30', 'none', '{\"content\":\"content\",\"paperSize\":\"A4\",\"lastModified\":\"2025-07-30T04:47:59.086Z\"}', '{\"locked_elements\":{\"content\":true,\"toc\":true,\"fontSize\":false,\"fontStyle\":false,\"headerFooter\":false},\"allowAttachments\":false,\"includeTableOfContents\":false}', '[{\"key\":0,\"department\":\"Design\",\"mandatory\":false,\"stage\":1,\"participants\":[]},{\"key\":1,\"department\":\"Marketing\",\"mandatory\":false,\"stage\":1,\"participants\":[]}]', '{\"departmentImpacts\":[],\"affectedSystems\":[],\"implementationEffort\":\"medium\",\"trainingRequired\":false}', NULL, '{\"reviewers\":[{\"userId\":18,\"name\":\"Jane  Doe\",\"email\":\"jane.doe@test.com\",\"department\":\"Finance\",\"role\":\"template_reviewer\",\"status\":\"pending\",\"dueDate\":\"2025-07-30T16:00:00.000Z\"},{\"userId\":6,\"name\":\"Daniel Ventura\",\"email\":\"daniel.projects@gmail.com\",\"department\":\"Design\",\"role\":\"template_reviewer\",\"status\":\"pending\",\"dueDate\":\"2025-07-30T16:00:00.000Z\"}],\"approvers\":[]}', '{\"content\":\"content\",\"paperSize\":\"A4\",\"lastModified\":\"2025-07-30T04:47:59.086Z\"}', 1, NULL, 1, '2025-07-30 04:48:17', '2025-07-30 04:48:17', 'pending_review', NULL),
('14cdd88d-52e1-4ccc-a12b-630ac29cb682', 1, 'neww', 'new', '{\"content\":\"new content\",\"paperSize\":\"A4\",\"lastModified\":\"2025-06-07T02:47:32.923Z\"}', '{\"locked_elements\":{\"content\":false,\"fontSize\":false,\"fontStyle\":false,\"borders\":false,\"headerFooter\":false},\"allowAttachments\":false,\"includeTableOfContents\":false}', '[]', '{\"departmentImpacts\":[],\"affectedSystems\":[],\"implementationEffort\":\"medium\",\"trainingRequired\":false,\"impactNotes\":\"\"}', '', '[]', '{\"content\":\"new content\"}', 1, NULL, 1, '2025-06-07 02:47:25', '2025-06-07 03:20:51', 'draft', NULL),
('1a7f91c4-38f9-467e-a0bc-1e4b75124784', 1, 'toaster', 'project', '{\"content\":\"<h2 id=\\\"heading-0\\\" style=\\\"box-sizing: inherit; margin-right: auto; margin-bottom: 32px; margin-left: auto; line-height: 39px; font-family: europa; font-weight: bold; font-size: 26px; color: rgb(17, 17, 17); padding-top: 40px;\\\">The Toaster Project</h2><p style=\\\"box-sizing: inherit; font-size: 21px; line-height: 34.65px; margin: 24px auto; color: rgb(17, 17, 17); font-family: minion-pro, serif;\\\">The victory was short-lived.</p><p style=\\\"box-sizing: inherit; font-size: 21px; line-height: 34.65px; margin: 24px auto; color: rgb(17, 17, 17); font-family: minion-pro, serif;\\\">When it came time to create the plastic case for his toaster, Thwaites realized he would need crude oil to make the plastic. This time, he called up BP and asked if they would fly him out to an oil rig and lend him some oil for the project. They immediately refused. It seems oil companies aren’t nearly as generous as iron mines.</p><p style=\\\"box-sizing: inherit; font-size: 21px; line-height: 34.65px; margin: 24px auto; color: rgb(17, 17, 17); font-family: minion-pro, serif;\\\">Thwaites had to settle for collecting plastic scraps and melting them into the shape of his toaster case. This is not as easy as it sounds. The homemade toaster ended up looking more like a melted cake than a kitchen appliance.</p><div><br></div>\",\"paperSize\":\"A4\",\"lastModified\":\"2025-05-28T04:14:24.843Z\"}', '{\"locked_elements\":{\"content\":false,\"fontSize\":true,\"fontStyle\":false,\"borders\":true,\"headerFooter\":false},\"allowAttachments\":false,\"includeTableOfContents\":true}', '[{\"key\":0,\"department\":\"Design\",\"mandatory\":false,\"stage\":1,\"participants\":[]},{\"key\":1,\"department\":\"Engineering\",\"mandatory\":false,\"stage\":1,\"participants\":[]}]', '{\"departmentImpacts\":[],\"affectedSystems\":[],\"implementationEffort\":\"medium\",\"trainingRequired\":false,\"impactNotes\":\"\"}', '', '[]', '{\"content\":\"<h2 id=\\\"heading-0\\\" style=\\\"box-sizing: inherit; margin-right: auto; margin-bottom: 32px; margin-left: auto; line-height: 39px; font-family: europa; font-weight: bold; font-size: 26px; color: rgb(17, 17, 17); padding-top: 40px;\\\">The Toaster Project</h2><p style=\\\"box-sizing: inherit; font-size: 21px; line-height: 34.65px; margin: 24px auto; color: rgb(17, 17, 17); font-family: minion-pro, serif;\\\">The victory was short-lived.</p><p style=\\\"box-sizing: inherit; font-size: 21px; line-height: 34.65px; margin: 24px auto; color: rgb(17, 17, 17); font-family: minion-pro, serif;\\\">When it came time to create the plastic case for his toaster, Thwaites realized he would need crude oil to make the plastic. This time, he called up BP and asked if they would fly him out to an oil rig and lend him some oil for the project. They immediately refused. It seems oil companies aren’t nearly as generous as iron mines.</p><p style=\\\"box-sizing: inherit; font-size: 21px; line-height: 34.65px; margin: 24px auto; color: rgb(17, 17, 17); font-family: minion-pro, serif;\\\">Thwaites had to settle for collecting plastic scraps and melting them into the shape of his toaster case. This is not as easy as it sounds. The homemade toaster ended up looking more like a melted cake than a kitchen appliance.</p><div><br></div>\",\"paperSize\":\"A4\",\"lastModified\":\"2025-05-28T04:14:24.843Z\"}', 1, NULL, 1, '2025-05-22 02:17:32', '2025-06-06 07:18:03', 'archived', NULL),
('286e6b58-45fd-4fa6-a5a1-d123497bc64c', 1, 'Template 1 more time', 'template', '{\"content\":\"this is the <span class=\\\"highlighted-text\\\" data-comment-id=\\\"comment-1748581204746-wgxjmr9fq\\\" data-fragment-id=\\\":~:text=this%20is%20the,content\\\">content</span>\",\"comments\":[{\"id\":\"comment-1748756878089-vfzx3s3uv\",\"text\":\"this\",\"highlightedText\":\"content\",\"fragmentId\":\"text-1748756873935-q73b0yssr\",\"timestamp\":\"2025-06-01T05:47:58.089Z\",\"user\":\"Daniel Ventura\",\"email\":\"danielventura09022002@gmail.com\",\"avatar\":null,\"status\":\"open\",\"replies\":[{\"id\":\"reply-1748832604554-2ryg01kw8\",\"text\":\"yess\",\"timestamp\":\"2025-06-02T02:50:04.554Z\",\"user\":\"Jane  Doe\",\"email\":\"jane.doe@test.com\",\"avatar\":null}]},{\"id\":\"comment-1748756920992-smdhyuvjj\",\"text\":\"it\",\"highlightedText\":\"is\",\"fragmentId\":\"text-1748756917015-dt61gfuv0\",\"timestamp\":\"2025-06-01T05:48:40.992Z\",\"user\":\"Daniel Ventura\",\"email\":\"danielventura09022002@gmail.com\",\"avatar\":null,\"status\":\"open\",\"replies\":[]},{\"id\":\"comment-1748833118726-7kvh9kexh\",\"text\":\"i dont like this\",\"highlightedText\":\"this\",\"fragmentId\":\"text-1748833107068-91agpszlo\",\"timestamp\":\"2025-06-02T02:58:38.726Z\",\"user\":\"Jane  Doe\",\"email\":\"jane.doe@test.com\",\"avatar\":null,\"status\":\"open\",\"replies\":[]},{\"id\":\"comment-1748841039952-81btwtk9f\",\"text\":\"yeas\\n\",\"highlightedText\":\"content\",\"fragmentId\":\"text-1748841033955-4lz1s791g\",\"timestamp\":\"2025-06-02T05:10:39.952Z\",\"user\":\"Jane  Doe\",\"email\":\"jane.doe@test.com\",\"avatar\":null,\"status\":\"open\",\"replies\":[]}]}', '{\"locked_elements\":{\"content\":true,\"fontSize\":true,\"fontStyle\":true,\"borders\":true,\"headerFooter\":true},\"allowAttachments\":false,\"includeTableOfContents\":true}', '[{\"key\":0,\"department\":\"Design\",\"mandatory\":false,\"stage\":1,\"participants\":[]},{\"key\":1,\"department\":\"Engineering\",\"mandatory\":false,\"stage\":1,\"participants\":[]},{\"key\":2,\"department\":\"Finance\",\"mandatory\":false,\"stage\":1,\"participants\":[]}]', '{\"departmentImpacts\":[],\"affectedSystems\":[],\"implementationEffort\":\"medium\",\"trainingRequired\":false,\"impactNotes\":\"\"}', 'note', '[]', '{\"content\":\"this is the <span class=\\\"highlighted-text\\\" data-comment-id=\\\"comment-1748581204746-wgxjmr9fq\\\" data-fragment-id=\\\":~:text=this%20is%20the,content\\\">content</span>\",\"comments\":[{\"id\":\"comment-1748756878089-vfzx3s3uv\",\"text\":\"this\",\"highlightedText\":\"content\",\"fragmentId\":\"text-1748756873935-q73b0yssr\",\"timestamp\":\"2025-06-01T05:47:58.089Z\",\"user\":\"Daniel Ventura\",\"email\":\"danielventura09022002@gmail.com\",\"avatar\":null,\"status\":\"open\",\"replies\":[{\"id\":\"reply-1748832604554-2ryg01kw8\",\"text\":\"yess\",\"timestamp\":\"2025-06-02T02:50:04.554Z\",\"user\":\"Jane  Doe\",\"email\":\"jane.doe@test.com\",\"avatar\":null}]},{\"id\":\"comment-1748756920992-smdhyuvjj\",\"text\":\"it\",\"highlightedText\":\"is\",\"fragmentId\":\"text-1748756917015-dt61gfuv0\",\"timestamp\":\"2025-06-01T05:48:40.992Z\",\"user\":\"Daniel Ventura\",\"email\":\"danielventura09022002@gmail.com\",\"avatar\":null,\"status\":\"open\",\"replies\":[]},{\"id\":\"comment-1748833118726-7kvh9kexh\",\"text\":\"i dont like this\",\"highlightedText\":\"this\",\"fragmentId\":\"text-1748833107068-91agpszlo\",\"timestamp\":\"2025-06-02T02:58:38.726Z\",\"user\":\"Jane  Doe\",\"email\":\"jane.doe@test.com\",\"avatar\":null,\"status\":\"open\",\"replies\":[]},{\"id\":\"comment-1748841039952-81btwtk9f\",\"text\":\"yeas\\n\",\"highlightedText\":\"content\",\"fragmentId\":\"text-1748841033955-4lz1s791g\",\"timestamp\":\"2025-06-02T05:10:39.952Z\",\"user\":\"Jane  Doe\",\"email\":\"jane.doe@test.com\",\"avatar\":null,\"status\":\"open\",\"replies\":[]}]}', 1, NULL, 1, '2025-05-30 04:59:10', '2025-06-07 01:40:13', 'pending_revision', NULL),
